1	import { quote, claim, policyCap } from "./claim-office.js";
2	
3	type Customer = { yearsWithMHPCO: number; previousContract: boolean };
4	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type ClaimStep = { op: "claim"; policy: number; incident: { damages: { itemType: string; amount: number }[] } };
7	type Step = QuoteStep | ClaimStep;
8	type Scenario = { customer: { yearsWithMHPCO: number; previousContract?: boolean }; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	function readStdin(): Promise<string> {
14	  return new Promise((resolve) => {
15	    let buffer = "";
16	    process.stdin.on("data", (chunk) => {
17	      buffer += chunk;
18	    });
19	    process.stdin.on("end", () => resolve(buffer));
20	  });
21	}
22	
23	function normalizeCustomer(customer: Scenario["customer"]): Customer {
24	  return {
25	    yearsWithMHPCO: customer.yearsWithMHPCO,
26	    previousContract: customer.previousContract ?? false,
27	  };
28	}
29	
30	function processClaim(
31	  step: ClaimStep,
32	  steps: Step[],
33	  remainingCaps: Map<number, number>,
34	): ClaimResult {
35	  const policyItems = (steps[step.policy] as QuoteStep).items;
36	  const currentCap = remainingCaps.get(step.policy) ?? policyCap(policyItems);
37	  const result = claim({ remainingCap: currentCap, items: policyItems }, step.incident);
38	  remainingCaps.set(step.policy, result.remainingCap);
39	  return result;
40	}
41	
42	function runScenario(scenario: Scenario): { results: StepResult[] } {
43	  const customer = normalizeCustomer(scenario.customer);
44	  const results: StepResult[] = [];
45	  const steps = scenario.steps;
46	  const remainingCaps = new Map<number, number>();
47	  for (const step of steps) {
48	    if (step.op === "quote") {
49	      results.push({ premium: quote({ customer, items: step.items }) });
50	    } else if (step.op === "claim") {
51	      results.push(processClaim(step, steps, remainingCaps));
52	    }
53	  }
54	  return { results };
55	}
56	
57	async function main(): Promise<void> {
58	  const input = await readStdin();
59	  const scenario: Scenario = JSON.parse(input);
60	  const output = runScenario(scenario);
61	  process.stdout.write(JSON.stringify(output));
62	}
63	
64	main();
